-- Insert 94 new loaded strength exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('High-Bar Back Squat', 'high-bar-back-squat', 'Perform High-Bar Back Squat as a controlled, progressively loaded barbell strength pattern. The athlete creates tension before the first rep, moves through the range they can own, and finishes each repetition with the same posture and control they started with.', 'INTERMEDIATE', 8, 3, 5, 30, 120, 150, 'High-Bar Back Squat is a barbell strength exercise for heavy bilateral force production with a more upright torso and high lower-body loading ceiling. Use it when the training goal is force production, tissue capacity, and repeatable positions—not conditioning volume.', 'Primary subrole: Squat / Knee-Dominant Strength. Score Strength high. Explosiveness can receive secondary credit only when the delivery uses crisp intent, appropriate load, and full recovery without changing this into Output or conditioning.', 'Set your body first, move the bar with control, and make every rep look repeatable. Strong and sharp beats heavy and sloppy.', 'Barbell squat strength', 'capacity', 'squat_knee_dominant_strength', 'barbell_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion","trunk_bracing"],"primary_tissues":["quadriceps","glutes","adductors","spinal_erectors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_exhale_or_controlled_valsalva","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Coach High-Bar Back Squat as a strength-focused barbell pattern with deliberate setup, controlled range, and clean reset between reps.","setup":["Set the rack, bench, box, blocks, or bar height so the athlete can start and finish safely.","Load the bar conservatively for the athlete''s current pattern quality.","Establish stance, grip, brace, and eye line before the first rep.","Confirm the athlete has a clear re-rack, set-down, or bail plan."],"execution_steps":["Brace before the bar moves.","Move through the athlete''s controllable range without chasing extra depth or range.","Keep the bar path consistent and the working joints aligned.","Finish the rep under control, reset breath and brace, then repeat."],"coach_cues":["Brace first.","Own the bar path.","Push the floor away.","Same rep every rep.","Stop before the rep gets ugly."],"common_faults":["Adding load before the setup is repeatable.","Rushing the eccentric or losing position at end range.","Turning a strength lift into a conditioning set.","Grinding through pain, dizziness, or obvious compensation."]}'::jsonb),
  ('Low-Bar Back Squat', 'low-bar-back-squat', 'Perform Low-Bar Back Squat as a controlled, progressively loaded barbell strength pattern. The athlete creates tension before the first rep, moves through the range they can own, and finishes each repetition with the same posture and control they started with.', 'INTERMEDIATE', 8, 3, 5, 30, 120, 150, 'Low-Bar Back Squat is a barbell strength exercise for maximal lower-body and hip strength with a strong posterior-chain contribution. Use it when the training goal is force production, tissue capacity, and repeatable positions—not conditioning volume.', 'Primary subrole: Squat / Knee-Dominant Strength. Score Strength high. Explosiveness can receive secondary credit only when the delivery uses crisp intent, appropriate load, and full recovery without changing this into Output or conditioning.', 'Set your body first, move the bar with control, and make every rep look repeatable. Strong and sharp beats heavy and sloppy.', 'Barbell squat strength', 'capacity', 'squat_knee_dominant_strength', 'barbell_squat_strength', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","trunk_bracing"],"primary_tissues":["glutes","adductors","hamstrings","spinal_erectors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_exhale_or_controlled_valsalva","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Coach Low-Bar Back Squat as a strength-focused barbell pattern with deliberate setup, controlled range, and clean reset between reps.","setup":["Set the rack, bench, box, blocks, or bar height so the athlete can start and finish safely.","Load the bar conservatively for the athlete''s current pattern quality.","Establish stance, grip, brace, and eye line before the first rep.","Confirm the athlete has a clear re-rack, set-down, or bail plan."],"execution_steps":["Brace before the bar moves.","Move through the athlete''s controllable range without chasing extra depth or range.","Keep the bar path consistent and the working joints aligned.","Finish the rep under control, reset breath and brace, then repeat."],"coach_cues":["Brace first.","Own the bar path.","Push the floor away.","Same rep every rep.","Stop before the rep gets ugly."],"common_faults":["Adding load before the setup is repeatable.","Rushing the eccentric or losing position at end range.","Turning a strength lift into a conditioning set.","Grinding through pain, dizziness, or obvious compensation."]}'::jsonb),
  ('Front Squat', 'front-squat', 'Perform Front Squat as a controlled, progressively loaded barbell strength pattern. The athlete creates tension before the first rep, moves through the range they can own, and finishes each repetition with the same posture and control they started with.', 'INTERMEDIATE', 8, 3, 5, 30, 120, 150, 'Front Squat is a barbell strength exercise for upright trunk strength, leg drive, and front-rack positional control. Use it when the training goal is force production, tissue capacity, and repeatable positions—not conditioning volume.', 'Primary subrole: Squat / Knee-Dominant Strength. Score Strength high. Explosiveness can receive secondary credit only when the delivery uses crisp intent, appropriate load, and full recovery without changing this into Output or conditioning.', 'Set your body first, move the bar with control, and make every rep look repeatable. Strong and sharp beats heavy and sloppy.', 'Front-rack squat strength', 'capacity', 'squat_knee_dominant_strength', 'front_rack_squat_strength', '{"primary_joint_actions":["knee_extension","hip_extension","front_rack_support","trunk_bracing"],"primary_tissues":["quadriceps","glutes","upper_back","anterior_core"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"braced_exhale_or_controlled_valsalva","balance_demand":"moderate_dynamic","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Coach Front Squat as a strength-focused barbell pattern with deliberate setup, controlled range, and clean reset between reps.","setup":["Set the rack, bench, box, blocks, or bar height so the athlete can start and finish safely.","Load the bar conservatively for the athlete''s current pattern quality.","Establish stance, grip, brace, and eye line before the first rep.","Confirm the athlete has a clear re-rack, set-down, or bail plan."],"execution_steps":["Brace before the bar moves.","Move through the athlete''s controllable range without chasing extra depth or range.","Keep the bar path consistent and the working joints aligned.","Finish the rep under control, reset breath and brace, then repeat."],"coach_cues":["Brace first.","Own the bar path.","Push the floor away.","Same rep every rep.","Stop before the rep gets ugly."],"common_faults":["Adding load before the setup is repeatable.","Rushing the eccentric or losing position at end range.","Turning a strength lift into a conditioning set.","Grinding through pain, dizziness, or obvious compensation."]}'::jsonb),
