  ('Dumbbell Farmer Carry', 'dumbbell-farmer-carry', 'Dumbbell Farmer Carry is a dumbbell-loaded strength exercise for loaded bracing and grip. Load, range, tempo, and rest should support force production rather than metabolic fatigue.', 'BEGINNER', 8, 3, NULL, 30, 90, 120, 'Bilateral loaded carry that builds grip, trunk stiffness, posture, and whole-body strength endurance. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: Carry / trunk loaded bracing strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not treat it as a jump, plyometric, or conditioning station.', 'Set position first, move the dumbbell with control, then finish every rep like you could repeat it cleanly.', 'Carry / Trunk Bracing Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'dumbbell_farmer_carry_strength', '{"primary_joint_actions":["loaded_locomotion","grip_hold","postural_bracing","hip_stability"],"primary_tissues":["forearms","traps","obliques","gluteals"],"primary_motor_control_demands":["bracing","position_ownership","load_path_control"],"postural_shape":"stacked_ribs_over_pelvis_with_task_specific_joint_positions","breathing_demand":"braced_exhale_on_effort","balance_demand":"loaded_dynamic_control","coordination_demand":"moderate_strength_patterning","impact_level":0}'::jsonb, '{"movement_description":"Dumbbell Farmer Carry: Bilateral loaded carry that builds grip, trunk stiffness, posture, and whole-body strength endurance. Use load that lets the athlete control the entire rep and finish with the same alignment they started with.","setup":["Select dumbbells that challenge posture without forcing leaning for Dumbbell Farmer Carry.","Stand tall, set ribs over pelvis, and grip the handles firmly.","Create a quiet foot tripod before stepping.","Clear the walking lane before beginning."],"execution_steps":["Walk with quiet, controlled steps while maintaining tall posture.","Keep the load from pulling the ribs, shoulders, or pelvis out of position.","Turn or set down with control rather than swinging the dumbbells.","End the set before grip or posture fails."],"coach_cues":["Own the setup before the rep.","Brace, then move the dumbbell.","Control down; drive up without losing shape.","Stop before strength turns into survival."],"common_faults":["Chasing load before position is repeatable.","Holding the breath for the entire set instead of bracing and breathing.","Rushing the eccentric or bouncing out of the bottom.","Leaning, rotating, or speed-walking to survive the load."]}'::jsonb),
  ('Dumbbell Suitcase Carry', 'dumbbell-suitcase-carry', 'Dumbbell Suitcase Carry is a dumbbell-loaded strength exercise for loaded bracing and grip. Load, range, tempo, and rest should support force production rather than metabolic fatigue.', 'BEGINNER', 8, 3, NULL, 30, 90, 120, 'Single-sided loaded carry that builds anti-lateral-flexion strength and gait control. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: Carry / trunk loaded bracing strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not treat it as a jump, plyometric, or conditioning station.', 'Set position first, move the dumbbell with control, then finish every rep like you could repeat it cleanly.', 'Carry / Trunk Bracing Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'dumbbell_suitcase_carry_strength', '{"primary_joint_actions":["loaded_locomotion","anti_lateral_flexion","grip_hold","pelvic_control"],"primary_tissues":["obliques","quadratus_lumborum","glute_medius","forearms"],"primary_motor_control_demands":["bracing","position_ownership","load_path_control"],"postural_shape":"stacked_ribs_over_pelvis_with_task_specific_joint_positions","breathing_demand":"braced_exhale_on_effort","balance_demand":"loaded_dynamic_control","coordination_demand":"moderate_strength_patterning","impact_level":0}'::jsonb, '{"movement_description":"Dumbbell Suitcase Carry: Single-sided loaded carry that builds anti-lateral-flexion strength and gait control. Use load that lets the athlete control the entire rep and finish with the same alignment they started with.","setup":["Select dumbbells that challenge posture without forcing leaning for Dumbbell Suitcase Carry.","Stand tall, set ribs over pelvis, and grip the handles firmly.","Create a quiet foot tripod before stepping.","Clear the walking lane before beginning."],"execution_steps":["Walk with quiet, 