  ('Dumbbell Dead Bug Pullover', 'dumbbell-dead-bug-pullover', 'Dumbbell Dead Bug Pullover is a dumbbell-loaded strength exercise for trunk stiffness under load. Load, range, tempo, and rest should support force production rather than metabolic fatigue.', 'BEGINNER', 8, 3, NULL, 25, 75, 100, 'Supine trunk-strength drill pairing a dumbbell pullover with dead-bug control. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: Carry / trunk loaded bracing strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not treat it as a jump, plyometric, or conditioning station.', 'Set position first, move the dumbbell with control, then finish every rep like you could repeat it cleanly.', 'Trunk / Loaded Bracing Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'dumbbell_dead_bug_pullover_strength', '{"primary_joint_actions":["anti_extension","shoulder_flexion_extension","contralateral_limb_control","rib_control"],"primary_tissues":["anterior_core","lats","hip_flexors","serratus_anterior"],"primary_motor_control_demands":["bracing","position_ownership","load_path_control"],"postural_shape":"stacked_ribs_over_pelvis_with_task_specific_joint_positions","breathing_demand":"braced_exhale_on_effort","balance_demand":"stable","coordination_demand":"moderate_strength_patterning","impact_level":0}'::jsonb, '{"movement_description":"Dumbbell Dead Bug Pullover: Supine trunk-strength drill pairing a dumbbell pullover with dead-bug control. Use load that lets the athlete control the entire rep and finish with the same alignment they started with.","setup":["Select a dumbbell load that allows complete control for Dumbbell Dead Bug Pullover.","Set the start position and brace before moving.","Keep breathing controlled and joints stacked.","Begin only when the athlete can hold the starting shape without symptoms."],"execution_steps":["Move through the prescribed range with slow control.","Maintain brace, joint stack, and steady breathing.","Return to the start position without swinging.","Stop when control or alignment breaks."],"coach_cues":["Own the setup before the rep.","Brace, then move the dumbbell.","Control down; drive up without losing shape.","Stop before strength turns into survival."],"common_faults":["Chasing load before position is repeatable.","Holding the breath for the entire set instead of bracing and breathing.","Rushing the eccentric or bouncing out of the bottom.","Range increases after control has already been lost."]}'::jsonb),
  ('Dumbbell Plank Pull-Through', 'dumbbell-plank-pull-through', 'Dumbbell Plank Pull-Through is a dumbbell-loaded strength exercise for trunk stiffness under load. Load, range, tempo, and rest should support force production rather than metabolic fatigue.', 'BEGINNER', 8, 3, NULL, 25, 75, 100, 'High-plank anti-rotation drill where the athlete drags a dumbbell across the body without shifting. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: Carry / trunk loaded bracing strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not treat it as a jump, plyometric, or conditioning station.', 'Set position first, move the dumbbell with control, then finish every rep like you could repeat it cleanly.', 'Trunk / Loaded Bracing Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'dumbbell_plank_pull_through_strength', '{"primary_joint_actions":["anti_rotation","plank_brace","cross_body_pull","scapular_stability"],"primary_tissues":["obliques","transverse_abdominis","serratus_anterior","lats"],"primary_motor_control_demands":["bracing","position_ownership","load_path_control"],"postural_shape":"stacked_ribs_over_pelvis_with_task_specific_joint_positions","breathing_demand":"braced_exhale_on_effort","balance_demand":"stable","coordination_demand":"moderate_strength_patterning","impact_level":0}'::jsonb, '{"movement_description":"Dumbbell Plank Pull-Through: High-plank anti-rotation drill where the athlete drags a dumbbell across the body without shifting. Use load that lets the athlete control the entire rep and finish with the same alignment they started with.","setup":["Select a dumbbell load that allows complete control for Dumbbell Plank Pull-Through.","Set the start position and brace before moving.","Keep breathing controlled and joints stacked.","Begin only when the athlete can hold the starting shape without symptoms."],"execution_steps":["Move through the prescribed range with slow control.","Maintain brace, joint stack, and steady breathing.","Return to the start position without swinging.","Stop when control or alignment breaks."],"coach_cues":["Own the setup before the rep.","Brace, then move the dumbbell.","Control down; drive up without losing shape.","Stop before strength turns into survival."],"common_faults":["Chasing load before position is repeatable.","Holding the breath for the entire set instead of bracing and breathing.","Rushing the eccentric or bouncing out of the bottom.","Range increases after control has already been lost."]}'::jsonb),
  ('Dumbbell Hollow-Body Pullover Hold', 'dumbbell-hollow-body-pullover-hold', 'Dumbbell Hollow-Body Pullover Hold is a dumbbell-loaded strength exercise for trunk stiffness under load. Load, range, tempo, and rest should support force production rather than metabolic fatigue.', 'BEGINNER', 8, 3, NULL, 25, 75, 100, 'Loaded hollow-position hold that builds trunk stiffness and shoulder-lat linkage. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: Carry / trunk loaded bracing strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not treat it as a jump, plyometric, or conditioning station.', 'Set position first, move the dumbbell with control, then finish every rep like you could repeat it cleanly.', 'Trunk / Loaded Bracing Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'dumbbell_hollow_body_pullover_hold_strength', '{"primary_joint_actions":["hollow_body_hold","anti_extension","shoulder_flexion_hold"],"primary_tissues":["anterior_core","lats","hip_flexors","serratus_anterior"],"primary_motor_control_demands":["bracing","position_ownership","load_path_control"],"postural_shape":"stacked_ribs_over_pelvis_with_task_specific_joint_positions","breathing_demand":"braced_exhale_on_effort","balance_demand":"stable","coordination_demand":"moderate_strength_patterning","impact_level":0}'::jsonb, '{"movement_description":"Dumbbell Hollow-Body Pullover Hold: Loaded hollow-position hold that builds trunk stiffness and shoulder-lat linkage. Use load that lets the athlete control the entire rep and finish with the same alignment they started with.","setup":["Select a dumbbell load that allows complete control for Dumbbell Hollow-Body Pullover Hold.","Set the start position and brace before moving.","Keep breathing controlled and joints stacked.","Begin only when the athlete can hold the starting shape without symptoms."],"execution_steps":["Move through the prescribed range with slow control.","Maintain brace, joint stack, and steady breathing.","Return to the start position without swinging.","Stop when control or alignment breaks."],"coach_cues":["Own the setup before the rep.","Brace, then move the dumbbell.","Control down; drive up without losing shape.","Stop before strength turns into survival."],"common_faults":["Chasing load before position is repeatable.","Holding the breath for the entire set instead of bracing and breathing.","Rushing the eccentric or bouncing out of the bottom.","Range increases after control has already been lost."]}'::jsonb),
  ('Dumbbell Windmill', 'dumbbell-windmill', 'Dumbbell Windmill is a dumbbell-loaded strength exercise for rotational control under load. Load, range, tempo, and rest should support force production rather than metabolic fatigue.', 'INTERMEDIATE', 8, 3, NULL, 25, 75, 100, 'Loaded hinge-rotation pattern that builds shoulder stability, trunk control, and hip strength through a long lever. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: Carry / trunk loaded bracing strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not treat it as a jump, plyometric, or conditioning station.', 'Set position first, move the dumbbell with control, then finish every rep like you could repeat it cleanly.', 'Rotational / Frontal Plane Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'dumbbell_windmill_strength', '{"primary_joint_actions":["hip_hinge","thoracic_rotation","overhead_stability","lateral_flexion_control"],"primary_tissues":["obliques","gluteals","hamstrings","rotator_cuff"],"primary_motor_control_demands":["bracing","position_ownership","load_path_control"],"postural_shape":"stacked_ribs_over_pelvis_with_task_specific_joint_positions","breathing_demand":"braced_exhale_on_effort","balance_demand":"loaded_dynamic_control","coordination_demand":"moderate_strength_patterning","impact_level":0}'::jsonb, '{"movement_description":"Dumbbell Windmill: Loaded hinge-rotation pattern that builds shoulder stability, trunk control, and hip strength through a long lever. Use load that lets the athlete control the entire rep and finish with the same alignment they started with.","setup":["Select a dumbbell load that allows complete control for Dumbbell Windmill.","Set the start position and brace before moving.","Keep breathing controlled and joints stacked.","Begin only when the athlete can hold the starting shape without symptoms."],"execution_steps":["Move slowly through the rotation or hinge path while keeping the dumbbell stacked.","Own the end range before returning.","Keep breathing behind the brace without collapsing the ribs.","Stop when shoulder, hip, or trunk position is no longer controlled."],"coach_cues":["Own the setup before the rep.","Brace, then move the dumbbell.","Control down; drive up without losing shape.","Stop before strength turns into survival."],"common_faults":["Chasing load before position is repeatable.","Holding the breath for the entire set instead of bracing and breathing.","Rushing the eccentric or bouncing out of the bottom.","Range increases after control has already been lost."]}'::jsonb),
  ('Dumbbell Turkish Get-Up to Tall Sit', 'dumbbell-turkish-get-up-to-tall-sit', 'Dumbbell Turkish Get-Up to Tall Sit is a dumbbell-loaded strength exercise for trunk stiffness under load. Load, range, tempo, and rest should support force production rather than metabolic fatigue.', 'INTERMEDIATE', 8, 3, NULL, 25, 75, 100, 'Partial get-up pattern that builds shoulder packing, trunk rotation control, and loaded body ownership. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.', 'Primary subrole: Carry / trunk loaded bracing strength. Score Strength high. Add a small Explosiveness score only when the coach uses crisp concentric intent, low fatigue, and adequate rest; do not treat it as a jump, plyometric, or conditioning station.', 'Set position first, move the dumbbell with control, then finish every rep like you could repeat it cleanly.', 'Integrated Trunk / Shoulder Strength', 'capacity', 'carry_trunk_loaded_bracing_strength', 'dumbbell_turkish_sit_up_strength', '{"primary_joint_actions":["loaded_roll_to_elbow","pressing_stack","trunk_rotation_control","shoulder_stability"],"primary_tissues":["obliques","deltoids","serratus_anterior","hip_flexors"],"primary_motor_control_demands":["bracing","position_ownership","load_path_control"],"postural_shape":"stacked_ribs_over_pelvis_with_task_specific_joint_positions","breathing_demand":"braced_exhale_on_effort","balance_demand":"stable","coordination_demand":"moderate_strength_patterning","impact_level":0}'::jsonb, '{"movement_description":"Dumbbell Turkish Get-Up to Tall Sit: Partial get-up pattern that builds shoulder packing, trunk rotation control, and loaded body ownership. Use load that lets the athlete control the entire rep and finish with the same alignment they started with.","setup":["Select a dumbbell load that allows complete control for Dumbbell Turkish Get-Up to Tall Sit.","Set the start position and brace before moving.","Keep breathing controlled and joints stacked.","Begin only when the athlete can hold the starting shape without symptoms."],"execution_steps":["Move through the prescribed range with slow control.","Maintain brace, joint stack, and steady breathing.","Return to the start position without swinging.","Stop when control or alignment breaks."],"coach_cues":["Own the setup before the rep.","Brace, then move the dumbbell.","Control down; drive up without losing shape.","Stop before strength turns into survival."],"common_faults":["Chasing load before position is repeatable.","Holding the breath for the entire set instead of bracing and breathing.","Rushing the eccentric or bouncing out of the bottom.","Range increases after control has already been lost."]}'::jsonb)
