-- Loaded strength cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'loaded_strength_readiness',
  NULL,
  'Loaded strength without conditioning drift or wrong phase intent',
  'Barbell and dumbbell Capacity strength must use intentional load, full rest, and strength-first scoring — not fatigue circuits, plyometric substitution, or Output-speed intent.',
  'Loaded strength cards span barbell and dumbbell squat, hinge, push, pull, carry, and trunk-accessory patterns for Capacity-phase force and tissue development.',
  'Strength reserve supports speed, jumping, and resilience when dosed correctly. Poor placement, short rest, or mis-tagged explosiveness trains sloppy mechanics and steals from Output work.',
  'Place after Prepare & Access, Skill, and true Output when in the same session. Score Strength high; add Explosiveness only with crisp concentric intent, low fatigue, and full recovery.',
  'Do not program heavy strength after conditioning, use high-rep burnout sets, or tag strength lifts as explosiveness when delivery is fatigued or slow.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
